using System.ComponentModel;
using ModelContextProtocol.Server;

namespace HttpMcpServer.Tools;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Returns a friendly greeting for the given name.")]
    public static string Greet(
        [Description("The name of the person to greet")] string name)
    {
        return $"Hello, {name}! Welcome to the MCP server.";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace HttpMcpServer.Resources;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration.")]
    public static string GetSettings()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { EnableCache = true, EnableLogging = true }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }
}

